// getSortedActiveBatches, getActiveBatch, getSellableStock — এখন src/logic.js থেকে import করা।

// ─── computeStockDeductionFIFO — একটা পণ্য থেকে qty বাদ দিলে নতুন stock/batches
// কী হবে তা বিশুদ্ধভাবে (pure function, কোনো state/side-effect নেই) হিসেব করে।
// 🔴 এন্টারপ্রাইজ-লেভেল ফিক্স (স্টক race condition): আগে এই FIFO deduction
// logic শুধু sale-completion কোডের ভেতরে (local `products` state থেকে) সরাসরি
// লেখা ছিল, আর ফলাফল সরাসরি `setProducts` দিয়ে স্থানীয়ভাবে বসিয়ে সেটাই
// generic diff-push দিয়ে Firestore-এ (absolute value হিসেবে) পাঠানো হতো।
// দুই ডিভাইস একই পণ্য প্রায় একই সময়ে বিক্রি করলে দুজনেই নিজের নিজের stale
// লোকাল stock থেকে হিসেব করত — শেষে যেটা Firestore-এ পৌঁছাত সেটাই জিতত, আরেকটার
// deduction সম্পূর্ণ হারিয়ে যেত (overselling ঝুঁকি) — ঠিক customer.balance-এ
// যে বাগ ছিল (এখন transactionUpdateBalance() দিয়ে ফিক্স করা) তারই প্যারালাল
// কেস। এই ফাংশনটাকে আলাদা করে বের করা হলো যাতে এটা:
//   ১. sale-এর সময় optimistic local UI আপডেটে ব্যবহার করা যায় (আগের মতোই), এবং
//   ২. FSS.transactionUpdateStock()-এর ভেতরে সার্ভারের বর্তমান (up-to-date)
//      product ডকুমেন্টে প্রয়োগ করে atomically লেখা যায় (নিচে দেখুন)।
function computeStockDeductionFIFO(product, qty) {
  if (!product || product.productType === "service") {
    return { newStock: product?.stock ?? 0, updatedBatches: product?.batches || [], batchNo: "", costPrice: product?.costPrice ?? 0 };
  }
  const newStock = Math.max(0, (product.stock || 0) - qty);
  let remaining = qty;
  const sortedBatches = getSortedActiveBatches(product);
  let batchNo = "", costPrice = product.costPrice ?? 0;
  if (sortedBatches.length > 0) {
    let calcRem = qty, totalC = 0, totalQ = 0;
    sortedBatches.forEach(b => {
      if (calcRem <= 0) return;
      const d = Math.min(calcRem, b.qty || 0);
      totalC += d * (b.costPrice ?? product.costPrice ?? 0);
      totalQ += d;
      calcRem -= d;
    });
    costPrice = totalQ > 0 ? totalC / totalQ : (product.costPrice ?? 0);
    batchNo = sortedBatches[0].batchNo || "";
  }
  const updatedBatches = sortedBatches
    .map(b => {
      if (remaining <= 0) return b;
      const deduct = Math.min(remaining, b.qty || 0);
      remaining -= deduct;
      return { ...b, qty: (b.qty || 0) - deduct };
    })
    .filter(b => b.qty > 0);
  return { newStock, updatedBatches, batchNo, costPrice };
}

// ─── smartMatch — fuzzy/contains scorer for Bengali+English ───────────────────
// Returns: 2=exact start, 1=contains/fuzzy, 0=no match
function smartMatch(text, query) {
  if (!query || !text) return query ? 0 : 1;
  const t = text.toLowerCase();
  const q = query.toLowerCase().trim();
  if (!q) return 1;
  if (t === q) return 3;
  if (t.startsWith(q)) return 2;
  if (t.includes(q)) return 1;
  // fuzzy: all chars of q appear in t in order
  let ti = 0, qi = 0;
  while (ti < t.length && qi < q.length) {
    if (t[ti] === q[qi]) qi++;
    ti++;
  }
  return qi === q.length ? 0.5 : 0;
}

// ─── HighlightText — query match এর অংশ highlight করে ──────────────────────
function HighlightText({ text, query, style, highlightColor = "#22c55e" }) {
  if (!query || !query.trim()) return <span style={style}>{text}</span>;
  const q = query.trim();
  const idx = text.toLowerCase().indexOf(q.toLowerCase());
  if (idx === -1) return <span style={style}>{text}</span>;
  return (
    <span style={style}>
      {text.slice(0, idx)}
      <span style={{ background: highlightColor + "44", color: highlightColor, fontWeight: 800, borderRadius: 3, padding: "0 1px" }}>
        {text.slice(idx, idx + q.length)}
      </span>
      {text.slice(idx + q.length)}
    </span>
  );
}

// 🔴 ফিক্স: সাপ্লায়ার নাম নরমালাইজেশন — "Square Pharmaceuticals Ltd." আর "Square
// Pharmaceuticals" এর মতো একই কোম্পানির সামান্য ভিন্ন বানান (Ltd./Limited/
// Pharmaceuticals/পাংচুয়েশন) আলাদা এন্ট্রি হিসেবে সাজেশনে দুইবার দেখাত। এই
// ফাংশন একটা "মূল নাম" (normalized key) বের করে — নিচে allSuppliers এই key
// দিয়ে ডিডুপ্লিকেট করে, তাই একই কোম্পানি এখন থেকে একবারই দেখাবে।
function normalizeSupplierKey(name) {
  return String(name || "")
    .toLowerCase()
    .replace(/[.,()]/g, "")
    .replace(/\b(ltd|limited|pharmaceuticals?|pharma|plc|inc|company|corporation|corp|group|bd|bangladesh)\b/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

// ─── SupplierPicker — টাইপাহেড সার্চ-করে-বাছাই সাপ্লায়ার সিলেক্টর ───────────
// BD_PHARMA_COMPANIES (MEDICINE_DATASET থেকে ডিরাইভ করা, ২১১টি) এর মধ্যে ফাজি সার্চ (smartMatch),
// অথবা "নিজে লিখুন" কাস্টম মোড।
function SupplierPicker({ value, onChange, error, T, S, autoFocus, extraSuppliers = [], businessType = "pharmacy" }) {
  const [open, setOpen] = useState(false);
  const [query, setQuery] = useState("");
  const { companies: BD_PHARMA_COMPANIES } = useMedicineDataset(businessType); // লেজি-লোড — এই পিকার খোলা হলেই ফেচ হয়
  // extraSuppliers = দোকানে আগে ম্যানুয়ালি লেখা কাস্টম সাপ্লায়ারের নাম (products/purchaseOrders থেকে) —
  // এগুলো তালিকায় যুক্ত হবে যাতে একবার লিখলে পরেরবার সাজেশনে দেখা যায় ("অটো-সেভ")
  // 🔴 ফিক্স: normalizeSupplierKey দিয়ে ডিডুপ্লিকেট — একই কোম্পানির একাধিক
  // ভ্যারিয়েন্ট (Ltd./পাংচুয়েশন ভিন্নতা) থাকলে একটাই canonical নাম রাখা হয়।
  // অগ্রাধিকার: (১) দোকানে আগে ব্যবহৃত নাম (extraSuppliers) ডেটাসেটের চেয়ে
  // প্রাধান্য পায় — কারণ সেটাই আপনার real ব্যবহার, (২) একই সোর্সের মধ্যে বেশি
  // সম্পূর্ণ (লম্বা) নামটা রাখা হয় (যেমন পূর্ণ "...Ltd." নাম)।
  const allSuppliers = useMemo(() => {
    const groups = new Map(); // normKey -> { name, fromExtra }
    const addName = (raw, fromExtra) => {
      const n = (raw || "").trim();
      if (!n) return;
      const key = normalizeSupplierKey(n) || n.toLowerCase();
      const existing = groups.get(key);
      if (!existing) {
        groups.set(key, { name: n, fromExtra });
      } else if (fromExtra && !existing.fromExtra) {
        groups.set(key, { name: n, fromExtra }); // দোকানের নিজের নামই canonical
      } else if (fromExtra === existing.fromExtra && n.length > existing.name.length) {
        groups.set(key, { name: n, fromExtra }); // বেশি সম্পূর্ণ নামটা রাখা
      }
    };
    extraSuppliers.forEach(s => addName(s, true));
    BD_PHARMA_COMPANIES.forEach(s => addName(s, false));
    return Array.from(groups.values()).map(g => g.name);
  }, [extraSuppliers, BD_PHARMA_COMPANIES]);
  const [customMode, setCustomMode] = useState(() => !!value && !allSuppliers.includes(value));

  const filtered = useMemo(() => {
    const q = query.trim();
    if (!q) return allSuppliers.slice(0, 30);
    return allSuppliers
      .map(c => ({ c, s: smartMatch(c, q) }))
      .filter(x => x.s > 0)
      .sort((a, b) => b.s - a.s)
      .slice(0, 30)
      .map(x => x.c);
  }, [query, allSuppliers]);

  if (customMode) {
    return (
      <div style={{ display: "flex", gap: 6, alignItems: "center" }}>
        <input style={{ ...S.input, flex: 1, marginBottom: 0, border: error ? "1.5px solid #ef4444" : S.input.border }}
          placeholder="সাপ্লায়ারের নাম লিখুন"
          defaultValue={value || ""}
          ref={el => { if (el && !el._b) { el._b = true;
            // বাংলা IME কম্পোজিশনের সাথে কনফ্লিক্ট এড়াতে uncontrolled ইনপুট — controlled হলে প্রতি
            // কি-স্ট্রোকে React re-render কম্পোজিশন ভেঙে দিতে পারে, ফলে টাইপ করা নাম সেভ হতো না।
            el.addEventListener("input", () => onChange(el.value), { passive: true });
            el.addEventListener("compositionend", () => onChange(el.value), { passive: true });
            el.addEventListener("blur", () => onChange(el.value), { passive: true });
          } }}
          onChange={() => {}}
          autoFocus={autoFocus !== false} autoComplete="off" />
        <button type="button" onClick={() => { setCustomMode(false); onChange(""); }}
          style={{ background: "none", border: `1px solid ${T.border}`, color: T.sub, borderRadius: 8, padding: "10px 10px", cursor: "pointer", fontSize: 12, fontFamily: "inherit", flexShrink: 0 }}>↩ তালিকা</button>
      </div>
    );
  }

  return (
    <div style={{ position: "relative" }}>
      <input
        style={{ ...S.input, marginBottom: 0, paddingRight: 30, border: error ? "1.5px solid #ef4444" : S.input.border }}
        placeholder="🔍 সাপ্লায়ার খুঁজুন..."
        value={open ? query : (value || "")}
        onFocus={() => { setQuery(""); setOpen(true); }}
        onChange={e => { setQuery(e.target.value); setOpen(true); }}
        onBlur={() => setTimeout(() => setOpen(false), 250)}
        autoComplete="off" />
      {value && !open && (
        <button type="button" tabIndex={-1}
          onMouseDown={e => { e.preventDefault(); onChange(""); setQuery(""); }}
          style={{ position: "absolute", right: 8, top: "50%", transform: "translateY(-50%)", background: "none", border: "none", color: "#64748b", cursor: "pointer", fontSize: 14, padding: 4 }}>✕</button>
      )}
      {open && (
        <div style={{ position: "absolute", top: "100%", left: 0, right: 0, background: T.card, border: `1px solid ${T.border}`, borderRadius: 12, zIndex: 200, maxHeight: 240, overflowY: "auto", boxShadow: "0 8px 24px rgba(0,0,0,0.4)", marginTop: 4 }}>
          <div onMouseDown={() => { setCustomMode(true); setOpen(false); }}
            style={{ padding: "10px 14px", cursor: "pointer", color: "#a78bfa", fontWeight: 700, fontSize: 13, borderBottom: `1px solid ${T.border}` }}>
            ✏️ নিজে লিখুন...
          </div>
          {filtered.length === 0 && (
            <div style={{ padding: "10px 14px", color: T.sub, fontSize: 12 }}>কোনো মিল পাওয়া যায়নি — উপরে "নিজে লিখুন" চাপুন</div>
          )}
          {filtered.map(c => (
            <div key={c} onMouseDown={() => { onChange(c); setOpen(false); }}
              style={{ padding: "10px 14px", cursor: "pointer", borderBottom: `1px solid ${T.border}`, fontSize: 13, color: T.text }}>
              <HighlightText text={c} query={query} highlightColor="#a78bfa" />
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// ── আগে ম্যানুয়ালি এন্ট্রি করা সাপ্লায়ারের নাম বের করা (products.company/supplier + purchaseOrders.supplier থেকে) ──
// SupplierPicker-এ extraSuppliers হিসেবে দিলে কাস্টম নাম "অটো-সেভ" হয়ে পরের বার সাজেশনে দেখা যায়
const getKnownSuppliers = (products = [], purchaseOrders = []) => {
  const set = new Set();
  (products || []).forEach(p => { const n = (p.company || p.supplier || "").trim(); if (n) set.add(n); });
  (purchaseOrders || []).forEach(po => { const n = (po.supplier || po.company || "").trim(); if (n) set.add(n); });
  return Array.from(set);
};

// computeSupplierDueMap — এখন src/logic.js থেকে import করা।

// ─── SearchBar — reusable smart search input component ───────────────────────
function SearchBar({ placeholder, value, onChange, onClear, color = "#22c55e", T, S, style, voiceColor, showCount, count, accentBorder, autoFocus }) {
  const [focused, setFocused] = React.useState(false);
  const inputRef = React.useRef(null);
  const { ref: smartRef } = useSmartSearch(onChange, 300); // 300ms debounce — Google/Linear approach

  const setRef = React.useCallback((el) => {
    inputRef.current = el;
    smartRef(el);
    if (el && autoFocus) setTimeout(() => el.focus(), 100);
  }, [smartRef, autoFocus]);

  const borderColor = focused ? color : (accentBorder || color + "44");
  const glowShadow  = focused ? `0 0 0 2.5px ${color}22, 0 2px 16px ${color}18` : `0 1px 4px rgba(0,0,0,0.15)`;

  return (
    <div style={{
      display: "flex", alignItems: "center", gap: 8,
      background: `linear-gradient(135deg,${color}08,${color}04)`,
      border: `1.5px solid ${borderColor}`,
      borderRadius: 14,
      padding: "9px 12px",
      transition: "all 0.2s cubic-bezier(0.4,0,0.2,1)",
      boxShadow: glowShadow,
      ...style,
    }}>
      {/* Search icon — pulses when focused */}
      <svg width="15" height="15" viewBox="0 0 24 24" fill="none"
        stroke={focused ? color : (S?.sub ? "#6b7280" : "#94a3b8")} strokeWidth="2.5" strokeLinecap="round"
        style={{ flexShrink: 0, transition: "stroke 0.2s", opacity: focused ? 1 : 0.7 }}>
        <circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/>
      </svg>

      <input
        ref={setRef}
        defaultValue={value}
        onChange={() => {}}
        placeholder={showCount && count !== undefined ? `${placeholder} (${count})` : placeholder}
        onFocus={() => setFocused(true)}
        onBlur={() => setFocused(false)}
        autoCorrect="off" autoCapitalize="off" spellCheck={false} autoComplete="off"
        inputMode="text"
        style={{
          flex: 1, background: "none", border: "none", outline: "none",
          color: T?.text || "#f1f5f9",
          fontSize: 13,
          fontFamily: "inherit",
          padding: 0,
          "::placeholder": { color: T?.sub || "#94a3b8" },
        }}
      />

      {/* Clear button — fades in when there's a value */}
      {value && (
        <button
          onPointerDown={e => { e.preventDefault(); }}
          onClick={() => { if (inputRef.current) { inputRef.current.value = ""; inputRef.current.focus(); } onClear?.(); onChange(""); }}
          style={{ background: color + "22", border: "none", color: color, cursor: "pointer", borderRadius: 8, width: 22, height: 22, fontSize: 11, fontWeight: 800, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, transition: "all 0.15s" }}>
          ✕
        </button>
      )}

      {/* Voice button slot */}
      {voiceColor && <VoiceSearchButton onResult={onChange} color={voiceColor} />}
    </div>
  );
}

// ─── Global Bengali Input Interceptor ────────────────────────────────────────
// Ridmik/Avro Android-এ compositionupdate fire হয় না।
// input event fire হয় isComposing=true সহ — React controlled input তখন
// DOM reset করে। Fix: React fiber থেকে onChange ধরে call করি, তারপর
// requestAnimationFrame-এ DOM value restore করি।
function installGlobalBengaliInterceptor() {
  if (window._sbmGlobalIME) return;
  window._sbmGlobalIME = true;

  function getReactOnChange(el) {
    const key = Object.keys(el).find(k => k.startsWith("__reactFiber") || k.startsWith("__reactInternalInstance"));
    if (!key) return null;
    let fiber = el[key];
    while (fiber) {
      const onChange = fiber.memoizedProps?.onChange;
      if (typeof onChange === "function") return onChange;
      fiber = fiber.return;
    }
    return null;
  }

  function getNativeSetter(el) {
    return Object.getOwnPropertyDescriptor(
      el.tagName === "TEXTAREA" ? HTMLTextAreaElement.prototype : HTMLInputElement.prototype, "value"
    )?.set;
  }

  function patch(el) {
    if (el._sbmIME) return;
    if (!el.matches("input[type='text'], input:not([type]), textarea")) return;
    el._sbmIME = true;

    // Ridmik অভ্র phonetic mode: composition চলাকালীন pending text
    // WebView InputConnection দিয়ে সরাসরি render হয় — কিন্তু Android WebView
    // একটা bug আছে: compositionupdate-এ pending text DOM-এ থাকলেও
    // visually render হয় না যতক্ষণ না repaint trigger হয়।
    // Fix: compositionupdate-এ opacity flicker দিয়ে force repaint করো।
    el.addEventListener("compositionupdate", () => {
      // Force WebView repaint — opacity 1 থেকে 0.999 তারপর আবার 1
      // এটা GPU layer invalidate করে pending text visible করে
      el.style.opacity = "0.999";
      requestAnimationFrame(() => { el.style.opacity = ""; });
    }, { passive: true });
  }

  document.querySelectorAll("input, textarea").forEach(patch);
  new MutationObserver(ms => ms.forEach(m => m.addedNodes.forEach(n => {
    if (n.nodeType !== 1) return;
    if (n.matches?.("input, textarea")) patch(n);
    n.querySelectorAll?.("input, textarea").forEach(patch);
  }))).observe(document.body, { childList: true, subtree: true });
}

// ─── Global Auto-Capitalize (English first letter) ─────────────────────────
// সব input/textarea-তে ইংরেজি লেখার সময় প্রথম অক্ষর স্বয়ংক্রিয়ভাবে বড় হাতের
// (capital) হয়ে যাবে। বাংলা টাইপিং, সংখ্যা, এবং number/password টাইপ ইনপুট
// এর উপর কোনো প্রভাব পড়বে না।
function installGlobalAutoCapitalize() {
  if (window._sbmAutoCap) return () => {};
  window._sbmAutoCap = true;

  function getNativeSetter(el) {
    return Object.getOwnPropertyDescriptor(
      el.tagName === "TEXTAREA" ? HTMLTextAreaElement.prototype : HTMLInputElement.prototype, "value"
    )?.set;
  }

  // React 16+ controlled input-এ programmatically value বদলালে React-এর
  // internal "_valueTracker" ও রিসেট করতে হয় — নাহলে React মনে করে value
  // বদলায়নি (তার নিজের cache অনুযায়ী "আগেই এই value ছিল"), ফলে পরের
  // synthetic event/re-render এ আগের (lowercase) value ফিরিয়ে আনে।
  function resetReactValueTracker(el) {
    try {
      const tracker = el._valueTracker;
      if (tracker) tracker.setValue("");
    } catch (_) {}
  }

  function eligible(el) {
    if (!el || (el.tagName !== "INPUT" && el.tagName !== "TEXTAREA")) return false;
    if (el.tagName === "INPUT") {
      const t = (el.type || "text").toLowerCase();
      // শুধু free-text টাইপের বক্সে কাজ করবে — number/password/date/email-pattern-sensitive বক্স বাদ
      if (!["text", "search", "tel", "url"].includes(t)) return false;
    }
    return true;
  }

  function applyCapitalize(el) {
    const val = el.value;
    if (!val) return;
    const first = val[0];
    if (first < "a" || first > "z") return; // ইংরেজি ছোট হাতের অক্ষর না হলে কিছু করার নেই
    const corrected = first.toUpperCase() + val.slice(1);
    if (corrected === val) return; // ইতিমধ্যে capital — কিছু করার দরকার নেই
    const pos = el.selectionStart, posEnd = el.selectionEnd;
    const setter = getNativeSetter(el);
    resetReactValueTracker(el);
    if (setter) setter.call(el, corrected); else el.value = corrected;
    try { el.setSelectionRange(pos, posEnd); } catch (_) {}
    // React-কে জানাতে সবসময় bubbling native "input" event dispatch করি —
    // fiber walk করে সরাসরি onChange কল করাটা অনির্ভরযোগ্য কারণ React
    // internal synthetic event object আশা করে যা আমরা বানাতে পারি না।
    el.dispatchEvent(new Event("input", { bubbles: true }));
  }

  // ── named handlers — cleanup-এর জন্য reference রাখা জরুরি ─────────────────
  const _capOnInput = (e) => {
    const el = e.target;
    if (!eligible(el)) return;
    if (e.isComposing) return; // composing চলাকালীন স্কিপ — অভ্র/রিদ্মিক/Gboard predictive ভাঙবে না
    applyCapitalize(el);
  };
  // Gboard/SwiftKey-এ ইংরেজি শব্দ টাইপের সময়ও autocorrect-এর জন্য composition span
  // চালু থাকে (isComposing=true থাকে পুরো শব্দ ধরে) — তাই উপরের "input" শোনা যথেষ্ট নয়,
  // composition শেষ হলে (word commit / স্পেস / blur) আবার চেক করতে হয়।
  const _capOnCompositionEnd = (e) => {
    const el = e.target;
    if (!eligible(el)) return;
    applyCapitalize(el);
  };
  // Fallback: ব্লার হওয়ার সময়ও একবার চেক — কোনো কীবোর্ডে compositionend ঠিকমতো না ফায়ার করলেও
  // শেষ মুহূর্তে প্রথম অক্ষর capital করে দেয়।
  const _capOnBlur = (e) => {
    const el = e.target;
    if (!eligible(el)) return;
    applyCapitalize(el);
  };

  document.addEventListener("input",          _capOnInput,          true);
  document.addEventListener("compositionend", _capOnCompositionEnd, true);
  document.addEventListener("blur",           _capOnBlur,           true);

  // ── cleanup: useEffect return-এ call করুন ────────────────────────────────
  return () => {
    window._sbmAutoCap = false;
    document.removeEventListener("input",          _capOnInput,          true);
    document.removeEventListener("compositionend", _capOnCompositionEnd, true);
    document.removeEventListener("blur",           _capOnBlur,           true);
  };
}

// ─── bnRef: Bengali IME-safe ref helper ──────────────────────────────────────
// setter শুধু compositionend + blur + non-composing input এ — typing এ re-render নেই
function bnRef(setter) {
  return (el) => {
    if (!el || el._sbmBengali) return;
    el._sbmBengali = true;
    el.addEventListener("compositionend", () => { setter(el.value); }, { passive: true });
    el.addEventListener("blur", () => { setter(el.value); }, { passive: true });
    el.addEventListener("input", (e) => { if (!e.isComposing) setter(el.value); }, { passive: true });
  };
}
