// ─── Device ID Layer (Multi-Device Support) ───────────────────────────────────
// প্রতিটি ডিভাইসের আলাদা ID, যাতে ৫টি ডিভাইস একসাথে সিঙ্ক করতে পারে
// 🔥 ফিক্স: শুধু raw localStorage ব্যবহার করায় Capacitor WebView-তে মাঝে মাঝে
// id হারিয়ে যেতো (প্রতিবার নতুন id তৈরি হতো — Active Devices লিস্টে duplicate দেখাতো)।
// এখন app বুট হওয়ার সময় IndexedDB-ভিত্তিক প্রধান storage থেকেও restore/sync করা হয়।
const DeviceID = (() => {
  const KEY = "sbm-device-id";
  let _id = null;
  return {
    get() {
      if (_id) return _id;
      try {
        let id = localStorage.getItem(KEY);
        if (!id) {
          id = "dev_" + Math.random().toString(36).slice(2, 10) + "_" + Date.now().toString(36);
          localStorage.setItem(KEY, id);
        }
        _id = id;
        return id;
      } catch { return "dev_default"; }
    },
    // app বুট হওয়ার সময় একবার কল করা হয় — IndexedDB-তে আগে থেকে id থাকলে সেটাই
    // ব্যবহার করে (localStorage-এ হারিয়ে গেলেও), না থাকলে বর্তমান id IndexedDB-তেও সেভ করে।
    async init() {
      try {
        const stored = await load("sbm-device-id-persistent");
        if (stored && typeof stored === "string") {
          _id = stored;
          try { localStorage.setItem(KEY, stored); } catch {}
        } else {
          const current = this.get();
          await save("sbm-device-id-persistent", current);
        }
      } catch {}
    }
  };
})();

// ─── FSS — Firestore Per-Record Sync Layer (replaces RT/RTDB array-sync) ────
// প্রতিটা collection-এর প্রতিটা ডকুমেন্ট আলাদাভাবে sync হয় (record-level) —
// সম্পূর্ণ array কখনো ওভাররাইট হয় না। তাই দুই ফোন একই সময়ে আলাদা রেকর্ড
// বদলালেও কোনো conflict/data-loss/mismatch হয় না। Firestore SDK-এর built-in
// IndexedDB persistence থাকায় নেট না থাকলেও লোকালে কাজ করে, নেট ফিরলে
// নিজে থেকেই sync হয়ে যায় — কোনো polling বা manual reseed লাগে না।
// Collections: customers, products, invoices, txns, smsLog, users, suppliers,
// purchaseOrders, stockMovements, cashLogs, paymentInvoices + settings/main
// (shopName, smsTemplates, smsGateway)
// FSS_COLLECTIONS, BACKUP_FIELDS, pickBackupFields — এখন src/sync.js থেকে
// import হয় (উপরে দেখুন)। FSS_COLLECTIONS-এর থেকে BACKUP_FIELDS ইচ্ছাকৃতভাবে
// আলাদা: FSS_COLLECTIONS ব্যবহৃত হয় Firestore-লেভেল অপারেশনে (clearAllData/
// Master Reset সহ) যেখানে "users" অন্তর্ভুক্ত করলে Master Reset স্টাফ/অ্যাডমিন
// লগইন ডেটাও মুছে দিত — যা অপ্রত্যাশিত আচরণ পরিবর্তন হতো।
// ── রিস্টোর গার্ড (বাগ ফিক্স) ────────────────────────────────────────────────
// সমস্যা: ম্যানুয়াল রিস্টোর (Google Drive/লোকাল ফাইল/স্ন্যাপশট) local state
// ছোট করে দিলে, useFSSCollection-এর push effect ব্যাকআপে-না-থাকা রেকর্ডকে
// "ইউজার মুছে দিয়েছে" ধরে নিয়ে Firestore থেকেও ডিলিট করে দিত — যা রিয়েল-টাইমে
// বাকি সব ডিভাইসেও ছড়িয়ে পড়ত। এই গার্ড চালু থাকা অবস্থায় push effect শুধু
// নতুন/বদলানো রেকর্ড পুশ করে, কোনো ডিলিট চালায় না (merge-only) — Master
// Sync-এর record-by-record merge লজিকের মতোই আচরণ। ট্রেড-অফ: এটা "ব্যাকআপে
// না-থাকা রেকর্ড বাদ দেওয়া"-কে আর গ্যারান্টি দেয় না, শুধু ভুল/পুরনো ব্যাকআপ
// রিস্টোর করলে মাস-ডিলিট হওয়া ঠেকায় — যা ইচ্ছাকৃত সিদ্ধান্ত (সেফটি > সম্পূর্ণতা)।
const RestoreGuard = { active: false, _timer: null };
function beginRestoreGuard(ms = 5000) {
  RestoreGuard.active = true;
  clearTimeout(RestoreGuard._timer);
  RestoreGuard._timer = setTimeout(() => { RestoreGuard.active = false; }, ms);
}
// রিস্টোরের সময় d[f] পাওয়া গেলে সংশ্লিষ্ট setF() setter কল করে — GoogleDriveSection/
// LocalStorageSection-এর সব restore পাথ (handleRestore, handleRestoreSnapshot,
// applyRestoredData) এটাই ব্যবহার করে, প্রতিটাতে আলাদা করে ১৮ লাইন if-চেইন নেই।
// এটাই সব restore পাথের একক চোকপয়েন্ট, তাই beginRestoreGuard() এখানেই বসানো —
// আলাদা করে প্রতিটা restore ফাংশনে বসাতে হয়নি।
function applyBackupFields(d, setters) {
  if (!d || !setters) return;
  // 🆕 ফিক্স: আগে fixed ৫ সেকেন্ড গার্ড থাকত — অনেক রেকর্ডের বড় ব্যাকআপে Firestore
  // push শেষ হতে ৫ সেকেন্ডের বেশি সময় লাগলে গার্ড উঠে যাওয়ার পর বাকি রেকর্ড push
  // চলাকালীন সময়ে race condition-এর ঝুঁকি ছিল (ব্যাকআপে-না-থাকা রেকর্ড ভুলবশত
  // ডিলিট হয়ে যাওয়া)। এখন রেকর্ড-সংখ্যা অনুযায়ী adaptive — ছোট দোকানে কার্যত
  // আগের মতোই ৫ সেকেন্ড থাকে, বড় ডেটাসেটে বেশি সময় (সর্বোচ্চ ৩০ সেকেন্ড) দেয়।
  beginRestoreGuard(computeRestoreGuardMs(d));
  BACKUP_FIELDS.forEach(f => {
    if (d[f]) {
      const setterName = "set" + f[0].toUpperCase() + f.slice(1);
      setters[setterName]?.(d[f]);
    }
  });
}

// ══════════════════════════════════════════════════════════════════════════
// PHASE 2 — নির্ভরযোগ্যতা (Reliability)
// ══════════════════════════════════════════════════════════════════════════

// ── #১৩ স্টোরেজ কোটা হ্যান্ডলিং ──────────────────────────────────────────────
// localStorage/IndexedDB পূর্ণ হয়ে গেলে ব্রাউজার/ওয়েবভিউ যে এরর দেয় তা চেনার
// জন্য এই হেল্পার — চেনা গেলে retry করে লাভ নেই (জায়গা নিজে থেকে ফাঁকা হবে না),
// তাই withRetry এই কেসে সাথে সাথে থেমে যায় এবং ইউজারকে সরাসরি কার্যকর
// পরামর্শ দেওয়া হয় ("পুরনো ব্যাকআপ মুছুন")।
function isQuotaError(e) {
  if (!e) return false;
  const name = e.name || "";
  const msg  = (e.message || "").toLowerCase();
  return name === "QuotaExceededError"
      || name === "NS_ERROR_DOM_QUOTA_REACHED"
      || msg.includes("quota")
      || msg.includes("no space") // Capacitor Filesystem-এর ডিভাইস-স্টোরেজ-পূর্ণ এরর
      || msg.includes("disk full");
}

const StorageQuota = {
  // navigator.storage.estimate() — সব ব্রাউজার/ওয়েবভিউতে নেই, তাই best-effort
  async check() {
    try {
      if (typeof navigator !== "undefined" && navigator.storage?.estimate) {
        const { usage = 0, quota = 0 } = await navigator.storage.estimate();
        const pct = quota ? (usage / quota) * 100 : 0;
        return { ok: true, usage, quota, pct, low: quota > 0 && pct > 90 };
      }
    } catch {}
    return { ok: false, usage: 0, quota: 0, pct: 0, low: false };
  },
  // ব্যর্থতার কারণ কোটা-জনিত কিনা বুঝে ইউজার-বান্ধব বার্তা বানায়
  friendlyMessage(e) {
    if (isQuotaError(e)) {
      return "ডিভাইসের স্টোরেজ প্রায় পূর্ণ — সেটিংস থেকে পুরনো ব্যাকআপ/স্ন্যাপশট মুছে জায়গা খালি করুন।";
    }
    return e?.message || "অজানা এরর";
  },
};

// ── #৫ রিট্রাই + এক্সপোনেনশিয়াল ব্যাকঅফ ────────────────────────────────────
// স্লো/অস্থির নেটওয়ার্কে একবার ব্যর্থ হলেই পুরো ব্যাকআপ আটকে না গিয়ে কয়েকবার
// (ডিফল্ট ৩ বার) আবার চেষ্টা করে, প্রতিবার আগেরটার দ্বিগুণ অপেক্ষা করে (jitter
// সহ, যাতে একসাথে অনেক রিট্রাই আবার একসাথেই আছড়ে না পড়ে)। কোটা-জনিত এরর হলে
// (#১৩) সাথে সাথে থেমে যায় — retry করে লাভ নেই।
async function withRetry(fn, { retries = 3, baseDelay = 800, onRetry } = {}) {
  let lastErr;
  for (let attempt = 0; attempt <= retries; attempt++) {
    try {
      return await fn(attempt);
    } catch (e) {
      lastErr = e;
      if (isQuotaError(e) || attempt === retries) break;
      onRetry?.(attempt + 1, e);
      const delay = baseDelay * Math.pow(2, attempt) + Math.random() * 250;
      await new Promise(r => setTimeout(r, delay));
    }
  }
  throw lastErr;
}

