function PdfActionBar({ htmlContent, title, T, S }) {
  const [busy, setBusy] = React.useState(false);
  const [dlMsg, setDlMsg] = React.useState("");
  const doAction = async (action) => {
    if (busy) return;
    setBusy(true);
    setDlMsg("");
    try {
      if (action === "print") {
        printPdfHtml(htmlContent);
      } else if (action === "whatsapp") {
        await sharePdfWhatsApp(htmlContent, title);
      } else if (action === "download") {
        const result = await downloadAsPdf(htmlContent, title);
        setDlMsg(result.msg);
        setTimeout(() => setDlMsg(""), 4000);
      }
    } finally { setTimeout(() => setBusy(false), 1200); }
  };
  return (
    <div style={{ marginTop: 12, background: "rgba(0,0,0,0.25)", borderRadius: 14, padding: "10px 10px 8px", border: "1px solid rgba(255,255,255,0.07)", backdropFilter: "blur(8px)" }}>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>
        <button
          style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 6,
            background: busy ? "#1e40af88" : "linear-gradient(135deg,#1e40af,#3b82f6)", color: "#fff",
            border: "none", borderRadius: 12, padding: "11px 8px", fontWeight: 800,
            cursor: busy ? "not-allowed" : "pointer", fontFamily: "inherit", fontSize: 13,
            boxShadow: busy ? "none" : "0 4px 14px rgba(59,130,246,0.45)",
            transition: "all 0.2s", opacity: busy ? 0.65 : 1 }}
          onClick={() => doAction("print")} disabled={busy}>
          <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round"><path d="M6 9V2h12v7M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2M6 14h12v8H6z"/></svg>
          {busy ? "..." : "Print"}
        </button>
        <button
          style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 6,
            background: busy ? "#05603a88" : "linear-gradient(135deg,#065f46,#22c55e)", color: "#fff",
            border: "none", borderRadius: 12, padding: "11px 8px", fontWeight: 800,
            cursor: busy ? "not-allowed" : "pointer", fontFamily: "inherit", fontSize: 13,
            boxShadow: busy ? "none" : "0 4px 14px rgba(34,197,94,0.45)",
            transition: "all 0.2s", opacity: busy ? 0.65 : 1 }}
          onClick={() => doAction("whatsapp")} disabled={busy}>
          <svg width="15" height="15" viewBox="0 0 24 24" fill="#fff"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 0 1-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 0 1-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 0 1 2.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0 0 12.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 0 0 5.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 0 0-3.48-8.413z"/></svg>
          {busy ? "..." : "WhatsApp"}
        </button>
      </div>
      {dlMsg && (
        <div style={{ marginTop: 8, background: "#22c55e18", color: "#16a34a", borderRadius: 8,
          padding: "7px 12px", fontSize: 12, fontWeight: 600, textAlign: "center", whiteSpace: "pre-line" }}>
          {dlMsg}
        </div>
      )}
    </div>
  );
}

// ─── 🔐 E2E Backup Encryption — AES-256-GCM via Web Crypto API ────────────────
// Owner-এর PIN থেকে key derive (PBKDF2) — কোনো key Anthropic/Firebase-এ যায় না,
// শুধু device-এই থাকে। PIN ভুলে গেলে backup আর decrypt করা যাবে না — তাই
// encrypt করার সময় ব্যবহারকারীকে এই সতর্কতা স্পষ্টভাবে দেখানো জরুরি।
const CRYPTO_MAGIC = "SBM-ENC-V1"; // ফাইল চিনতে — plain backup vs encrypted backup
const PBKDF2_ITERATIONS = 600000; // 🔒 আগে ১ লাখ (2017 OWASP) ছিল — বর্তমান standard (SHA-256) অনুযায়ী বাড়ানো হয়েছে

async function deriveKeyFromPin(pin, saltBytes) {
  const enc = new TextEncoder();
  const keyMaterial = await crypto.subtle.importKey(
    "raw", enc.encode(pin), "PBKDF2", false, ["deriveKey"]
  );
  return crypto.subtle.deriveKey(
    { name: "PBKDF2", salt: saltBytes, iterations: PBKDF2_ITERATIONS, hash: "SHA-256" },
    keyMaterial,
    { name: "AES-GCM", length: 256 },
    false,
    ["encrypt", "decrypt"]
  );
}

function bufToBase64(buf) {
  let binary = "";
  const bytes = new Uint8Array(buf);
  for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
  return btoa(binary);
}
function base64ToBuf(b64) {
  const binary = atob(b64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  return bytes.buffer;
}

// data (plain JS object) → encrypted wrapper object, যেটা সরাসরি JSON.stringify করে সেভ করা যায়
async function encryptBackupData(data, pin) {
  const salt = crypto.getRandomValues(new Uint8Array(16));
  const iv   = crypto.getRandomValues(new Uint8Array(12));
  const key  = await deriveKeyFromPin(pin, salt);
  const plaintext = new TextEncoder().encode(JSON.stringify(data));
  const cipherBuf = await crypto.subtle.encrypt({ name: "AES-GCM", iv }, key, plaintext);
  return {
    _magic:   CRYPTO_MAGIC,
    _encrypted: true,
    salt:     bufToBase64(salt),
    iv:       bufToBase64(iv),
    data:     bufToBase64(cipherBuf),
    _meta: { version: 3, encryptedAt: new Date().toISOString(), algo: "AES-256-GCM" },
  };
}

// encrypted wrapper object + pin → আসল data object (অথবা throw করবে যদি ভুল pin)
async function decryptBackupData(encWrapper, pin) {
  if (!encWrapper?._encrypted || encWrapper._magic !== CRYPTO_MAGIC) {
    throw new Error("এটি এনক্রিপ্টেড ব্যাকআপ ফাইল নয়");
  }
  const salt = new Uint8Array(base64ToBuf(encWrapper.salt));
  const iv   = new Uint8Array(base64ToBuf(encWrapper.iv));
  const key  = await deriveKeyFromPin(pin, salt);
  try {
    const plainBuf = await crypto.subtle.decrypt(
      { name: "AES-GCM", iv }, key, base64ToBuf(encWrapper.data)
    );
    const text = new TextDecoder().decode(plainBuf);
    return JSON.parse(text);
  } catch (e) {
    throw new Error("ভুল PIN অথবা ফাইল ক্ষতিগ্রস্ত — ডিক্রিপ্ট করা যায়নি");
  }
}

// একটি object যদি encrypted wrapper কিনা চেক করতে (restore flow-এ আগে থেকেই জানতে)
function isEncryptedBackup(data) {
  return !!(data && data._encrypted === true && data._magic === CRYPTO_MAGIC);
}

function downloadBackupFile(data, filename) {
  // Browser fallback — Capacitor uses FS.saveBackup (called in performDriveBackup)
  const json = JSON.stringify(data, null, 2);
  const blob = new Blob([json], { type: "application/json" });
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement("a");
  a.href = url; a.download = filename; a.click();
  setTimeout(() => URL.revokeObjectURL(url), 1000);
}

// ─── recharts — লেজি-লোড (শুধু AI > Analytics ট্যাব খোলা হলে ফেচ হয়, বুট ব্লক করে না) ───
let _rechartsMod = null;
let _rechartsPromise = null;
const _rechartsListeners = new Set();
function ensureRecharts() {
  if (_rechartsMod || _rechartsPromise) return;
  _rechartsPromise = import("recharts")
    .then(mod => { _rechartsMod = mod; _rechartsListeners.forEach(fn => fn()); })
    .catch(() => {});
}
function useRecharts() {
  const [, force] = useState(0);
  useEffect(() => {
    if (_rechartsMod) return;
    ensureRecharts();
    const listener = () => force(v => v + 1);
    _rechartsListeners.add(listener);
    return () => { _rechartsListeners.delete(listener); };
  }, []);
  return _rechartsMod; // null যতক্ষণ না লোড হয়
}

// ─── Seeds ────────────────────────────────────────────────────────────────────
const PRODUCT_CATEGORIES = ["সব", "অ্যান্টিবায়োটিক", "ব্যথানাশক", "গ্যাস্ট্রিক", "ডায়াবেটিস", "ভিটামিন", "স্যালাইন", "ড্রেসিং", "সিরাপ", "চর্মরোগ", "হৃদরোগ", "অন্যান্য"];

// ─── MEDICINE_DATASET — নাম-ভিত্তিক অটো-সাজেশন ডেটাসেট (ও কোম্পানি/সাপ্লায়ার লিস্টের সোর্স) ──
// প্রতিটি এন্ট্রি: [নাম, পাওয়ার/শক্তি, কোম্পানি]। উৎস: MedEx.com.bd থেকে সংগৃহীত একটি ওপেন
// GitHub ডেটাসেট (mahfuj-m/Medicine-s-Dataset) — ২০,৫০০+ প্রকৃত/verified বাংলাদেশি ব্র্যান্ড এন্ট্রি,
// হাতে-বানানো/অনুমাননির্ভর কোনো ডেটা নেই। এই ফাইলটা (medicineDataset.json) App.jsx-এর পাশে repo-তে
// আলাদাভাবে যোগ করতে হবে — নাহলে বিল্ড ভাঙবে।
//
// 🔴 পারফরম্যান্স ফিক্স (কোল্ড-স্টার্ট): আগে এই ২০,৫০০+ এন্ট্রির JSON স্ট্যাটিক import হতো —
// মানে অ্যাপ খোলার সময়, প্রথম রেন্ডারের আগেই, পুরো ফাইলটা পার্স + দুইবার পুরো array-এর উপর
// .map() (LABELS_LC + BD_PHARMA_COMPANIES ডিরাইভ) সিঙ্ক্রোনাসভাবে চলত — এটা শুধু Products
// ফর্ম/SupplierPicker খুললে দরকার হয়, Dashboard/Customers/Invoice-এ লাগেই না। এখন dynamic
// import() দিয়ে লেজি-লোড হয় — শুধু যখন SupplierPicker বা "নতুন পণ্য" নাম-সাজেশন আসলেই খোলা
// হয়, তখনই ফেচ/পার্স হয়। বুট টাইম থেকে এই পুরো খরচটা সম্পূর্ণ সরে গেল।
let _medDataset = null;      // null = এখনো লোড হয়নি
let _medPromise  = null;
let _medLabelsLC = null;
let _medCompanies = null;
const _medListeners = new Set();
const EMPTY_MED_ARR = [];

// ─── 🐄 ভেটেরিনারি মোড — সেলফ-লার্নিং ডেটাসেট ──────────────────────────────
// বাংলাদেশে পাবলিকলি উপলব্ধ কোনো ভেরিফায়েড ভেটেরিনারি মেডিসিন ব্র্যান্ড
// ডেটাসেট পাওয়া যায়নি (Medex-ভিত্তিক ওপেন ডেটাসেটগুলো শুধু মানুষের ওষুধের)।
// তাই প্রোডাক্টের নাম হাতে-বানানো/অনুমাননির্ভর না রেখে — দোকানদার যা যা
// এন্ট্রি করবেন (নতুন পণ্য/পারচেজ) তা থেকেই ধীরে ধীরে সাজেশন লিস্ট গড়ে ওঠে
// (localStorage-এ সেভ থাকে, ডিভাইসেই)। শুধু সাপ্লায়ার/কোম্পানির একটা সীড
// লিস্ট দেওয়া আছে — বাংলাদেশের পরিচিত ভেটেরিনারি ওষুধ প্রস্তুতকারক কোম্পানি
// (সোর্স: The Business Standard-এর প্রতিবেদন, AHCAB রেফারেন্স সহ), কোনো
// নির্দিষ্ট প্রোডাক্ট/ব্র্যান্ড নাম নয় — সেগুলো সম্পূর্ণ সেলফ-লার্নড।
const VET_SEED_COMPANIES = [
  "এসিআই এনিমেল হেলথ", "রেনাটা এনিমেল হেলথ", "স্কয়ার ফার্মাসিউটিক্যালস (এনিমেল হেলথ)",
  "এসকায়েফ (SK+F) এনিমেল হেলথ", "অপসোনিন ফার্মা", "নাভানা ফার্মাসিউটিক্যালস",
  "পপুলার ফার্মাসিউটিক্যালস", "ইনসেপ্টা ফার্মাসিউটিক্যালস", "এসিএমই ল্যাবরেটরিজ (এগ্রোভেট)", "এল্যানকো বাংলাদেশ",
];
const VET_LEARNED_KEY = "sbm-vet-med-learned";
let _vetLearned = null; // null = এখনো localStorage থেকে পড়া হয়নি
// 🆕 vetMedicineDataset.json — BDNVF 2023 (DGDA) থেকে বের করা ভেরিফায়েড ব্র্যান্ড-নাম/কোম্পানি
// ডেটাসেট (~1100 এন্ট্রি)। medicineDataset.json-এর ঠিক একই লেজি-লোড প্যাটার্নে, App.jsx-এর
// পাশে repo-তে আলাদাভাবে বসবে — না থাকলে শুধু সেলফ-লার্নড ডেটাসেট দিয়েই কাজ চলবে (ফলব্যাক)।
let _vetDataset = null;  // null = এখনো লোড হয়নি
let _vetPromise  = null;
function ensureVetLearnedLoaded() {
  if (_vetLearned === null) {
    try {
      const raw = localStorage.getItem(VET_LEARNED_KEY);
      _vetLearned = raw ? JSON.parse(raw) : [];
    } catch { _vetLearned = []; }
  }
  return _vetLearned;
}
function saveVetLearned() {
  try { localStorage.setItem(VET_LEARNED_KEY, JSON.stringify(_vetLearned || [])); } catch {}
}
// দোকানদার নতুন পণ্য/পারচেজ এন্ট্রি করলে এখান থেকে কল হয় — [নাম, একক, কোম্পানি]
// আকারে সেভ হয়, পরের বার টাইপ করলেই সাজেশনে দেখাবে (কোনো ডুপ্লিকেট রাখা হয় না)
function vetLearnEntry(name, unit, company) {
  const n = String(name || "").trim();
  if (!n) return;
  const u = unit ? String(unit).trim() : "";
  const c = company ? String(company).trim() : "";
  const list = ensureVetLearnedLoaded();
  const row = list.find(([en, eu]) => en === n && (eu || "") === u);
  if (!row) {
    list.unshift([n, u, c]);
    if (list.length > 5000) list.length = 5000; // নিরাপত্তা সীমা
    saveVetLearned();
    _medListeners.forEach(fn => fn());
  } else if (c && !row[2]) {
    row[2] = c; // নাম আগে থেকেই আছে কিন্তু কোম্পানি ফাঁকা ছিল — এখন যোগ হলো
    saveVetLearned();
  }
}

// ─── 💊 ফার্মেসি মোড — সেলফ-লার্নিং ডেটাসেট (medicineDataset.json-এর পরিপূরক) ──────
// static ২০,৫০০+ এন্ট্রির dataset-এ না থাকা নতুন/লোকাল ব্র্যান্ড দোকানদার এন্ট্রি করলে
// এখান থেকেই ধীরে ধীরে শেখা হয় (localStorage, ডিভাইসেই) — ভেটেরিনারি মোডের প্যাটার্ন অনুসরণ করে
const MED_LEARNED_KEY = "sbm-pharm-med-learned";
let _medLearnedList = null; // null = এখনো localStorage থেকে পড়া হয়নি
function ensureMedLearnedLoaded() {
  if (_medLearnedList === null) {
    try {
      const raw = localStorage.getItem(MED_LEARNED_KEY);
      _medLearnedList = raw ? JSON.parse(raw) : [];
    } catch { _medLearnedList = []; }
  }
  return _medLearnedList;
}
function saveMedLearned() {
  try { localStorage.setItem(MED_LEARNED_KEY, JSON.stringify(_medLearnedList || [])); } catch {}
}
function medLearnEntry(name, unit, company) {
  const n = String(name || "").trim();
  if (!n) return;
  const u = unit ? String(unit).trim() : "";
  const c = company ? String(company).trim() : "";
  const list = ensureMedLearnedLoaded();
  const row = list.find(([en, eu]) => en === n && (eu || "") === u);
  if (!row) {
    list.unshift([n, u, c]);
    if (list.length > 5000) list.length = 5000; // নিরাপত্তা সীমা
    saveMedLearned();
    _medListeners.forEach(fn => fn());
  } else if (c && !row[2]) {
    row[2] = c; // নাম আগে থেকেই আছে কিন্তু কোম্পানি ফাঁকা ছিল — এখন যোগ হলো
    saveMedLearned();
  }
}
// businessType অনুযায়ী সঠিক লার্নিং স্টোরে পাঠায় — নতুন পণ্য/পারচেজ এন্ট্রির সময় কল হয়
function learnMedicineEntry(businessType, name, unit, company) {
  if (businessType === "veterinary") vetLearnEntry(name, unit, company);
  else medLearnEntry(name, unit, company);
}

function ensureMedicineDataset(businessType = "pharmacy") {
  if (businessType === "veterinary") {
    ensureVetLearnedLoaded(); // সিঙ্ক্রোনাস, সবসময় সাথে সাথে পাওয়া যায়
    if (_vetDataset || _vetPromise) return; // static ডেটাসেট আগেই লোড হয়েছে/হচ্ছে
    _vetPromise = import("./vetMedicineDataset.json")
      .then(mod => {
        _vetDataset = mod.default || mod;
        _medListeners.forEach(fn => fn());
      })
      .catch(() => {
        _vetDataset = EMPTY_MED_ARR; // ফাইল না থাকলেও চুপচাপ সেলফ-লার্নড দিয়েই কাজ চলবে
        _medListeners.forEach(fn => fn());
      });
    return;
  }
  ensureMedLearnedLoaded(); // সিঙ্ক্রোনাস — ফার্মেসির সেলফ-লার্নড এন্ট্রি সবসময় সাথে সাথে পাওয়া যায়
  if (_medDataset || _medPromise) return;
  _medPromise = import("./medicineDataset.json")
    .then(mod => {
      _medDataset = mod.default || mod;
      // দ্রুত সাজেশন-সার্চের জন্য লোয়ারকেস লেবেল প্রি-কম্পিউট (একবারই, লোড হওয়ার পরে)
      _medLabelsLC = _medDataset.map(([n, p]) => (p ? `${n} ${p}` : n).toLowerCase());
      _medCompanies = [...new Set(
        _medDataset.map(([, , company]) => company).filter(Boolean)
      )].sort((a, b) => a.localeCompare(b));
      _medListeners.forEach(fn => fn());
    })
    .catch(() => {
      _medDataset = EMPTY_MED_ARR; _medLabelsLC = EMPTY_MED_ARR; _medCompanies = EMPTY_MED_ARR;
      _medListeners.forEach(fn => fn());
    });
}
// কম্পোনেন্ট থেকে ব্যবহারের জন্য হুক — প্রথমবার কল হলেই লেজি-লোড ট্রিগার হয়, লোড শেষ হলে re-render
// businessType === "veterinary" হলে pharmacy JSON-এর বদলে সেলফ-লার্নড লোকাল ডেটাসেট ফেরত দেয়
function useMedicineDataset(businessType = "pharmacy") {
  const [, force] = useState(0);
  useEffect(() => {
    if (businessType === "veterinary") {
      ensureMedicineDataset(businessType); // learned (sync) + static vetMedicineDataset.json (লেজি)
      const listener = () => force(v => v + 1);
      _medListeners.add(listener);
      return () => { _medListeners.delete(listener); };
    }
    if (_medDataset) return;
    ensureMedicineDataset(businessType);
    const listener = () => force(v => v + 1);
    _medListeners.add(listener);
    return () => { _medListeners.delete(listener); };
  }, [businessType]);

  if (businessType === "veterinary") {
    const learned = _vetLearned || EMPTY_MED_ARR;
    const staticVet = _vetDataset || EMPTY_MED_ARR;
    // দোকানদার নিজে যা এন্ট্রি করেছেন (learned) সবচেয়ে প্রাসঙ্গিক — আগে রাখা হলো, তারপর
    // static BDNVF ডেটাসেট থেকে বাকিটা, নাম+স্ট্রেংথ ডুপ্লিকেট (case-insensitive) বাদ দিয়ে
    const seen = new Set();
    const merged = [];
    for (const row of learned) {
      const key = `${row[0]}|${row[1] || ""}`.toLowerCase();
      if (seen.has(key)) continue;
      seen.add(key);
      merged.push(row);
    }
    for (const row of staticVet) {
      const key = `${row[0]}|${row[1] || ""}`.toLowerCase();
      if (seen.has(key)) continue;
      seen.add(key);
      merged.push(row);
    }
    const labelsLC = merged.map(([n, p]) => (p ? `${n} ${p}` : n).toLowerCase());
    const staticCompanies = staticVet.map(([, , c]) => c).filter(Boolean);
    const learnedCompanies = learned.map(([, , c]) => c).filter(Boolean);
    const companies = [...new Set([...VET_SEED_COMPANIES, ...staticCompanies, ...learnedCompanies])].sort((a, b) => a.localeCompare(b, "bn"));
    return { dataset: merged, labelsLC, companies, ready: true };
  }
  const learnedMed = _medLearnedList || EMPTY_MED_ARR;
  const staticMed = _medDataset || EMPTY_MED_ARR;
  if (learnedMed.length === 0) {
    return {
      dataset:   staticMed,
      labelsLC:  _medLabelsLC  || EMPTY_MED_ARR,
      companies: _medCompanies || EMPTY_MED_ARR,
      ready: !!_medDataset,
    };
  }
  // দোকানদার নিজে নতুন যা এন্ট্রি করেছেন (learnedMed) — static ২০,৫০০+ dataset-এ না থাকা
  // ব্র্যান্ড/নাম এখান থেকেও সাজেশনে আসবে, আগে রাখা হলো, তারপর static, ডুপ্লিকেট বাদ দিয়ে
  const seenM = new Set();
  const mergedMed = [];
  for (const row of learnedMed) {
    const key = `${row[0]}|${row[1] || ""}`.toLowerCase();
    if (seenM.has(key)) continue;
    seenM.add(key);
    mergedMed.push(row);
  }
  for (const row of staticMed) {
    const key = `${row[0]}|${row[1] || ""}`.toLowerCase();
    if (seenM.has(key)) continue;
    seenM.add(key);
    mergedMed.push(row);
  }
  const mergedLabelsLC = mergedMed.map(([n, p]) => (p ? `${n} ${p}` : n).toLowerCase());
  const learnedCompaniesMed = learnedMed.map(([, , c]) => c).filter(Boolean);
  const mergedCompanies = [...new Set([...(_medCompanies || EMPTY_MED_ARR), ...learnedCompaniesMed])].sort((a, b) => a.localeCompare(b));
  return {
    dataset:   mergedMed,
    labelsLC:  mergedLabelsLC,
    companies: mergedCompanies,
    ready: true,
  };
}


// ─── medDatasetLabel — একটা এন্ট্রির প্রদর্শন টেক্সট (নাম + পাওয়ার) তৈরি করে ──────────
function medDatasetLabel(entry) {
  const [n, p] = entry;
  return p ? `${n} ${p}` : n;
}

// ─── medTypeAbbr — ওষুধের ধরন (Tablet/Capsule/Syrup ইত্যাদি, medicineDataset.json-এর
// ৪র্থ কলাম, MedEx থেকে সংগৃহীত) থেকে ছোট সংক্ষিপ্ত রূপ + রঙ বের করে — নামের শুরুতে
// প্রিফিক্স ব্যাজ হিসেবে দেখানোর জন্য (Tab/Cap/Syp ইত্যাদি, ধরনভেদে আলাদা রঙ)
function medTypeAbbr(type) {
  if (!type) return null;
  const t = String(type).toLowerCase();
  if (t.includes("tablet")) return { abbr: "Tab", color: "#38bdf8" };
  if (t.includes("capsule")) return { abbr: "Cap", color: "#a78bfa" };
  if (t.includes("syrup")) return { abbr: "Syp", color: "#f472b6" };
  if (t.includes("suspension")) return { abbr: "Susp", color: "#f472b6" };
  if (t.includes("elixir")) return { abbr: "Elixir", color: "#f472b6" };
  if (t.includes("injection") || t.includes("infusion")) return { abbr: "Inj", color: "#ef4444" };
  if (t.includes("cream")) return { abbr: "Cream", color: "#f59e0b" };
  if (t.includes("ointment")) return { abbr: "Oint", color: "#f59e0b" };
  if (t.includes("gel")) return { abbr: "Gel", color: "#f59e0b" };
  if (t.includes("lotion")) return { abbr: "Lotion", color: "#f59e0b" };
  if (t.includes("paste")) return { abbr: "Paste", color: "#f59e0b" };
  if (t.includes("drop")) return { abbr: "Drop", color: "#22d3ee" };
  if (t.includes("solution")) return { abbr: "Sol", color: "#22d3ee" };
  if (t.includes("inhaler") || t.includes("inhalation")) return { abbr: "Inhaler", color: "#22c55e" };
  if (t.includes("spray")) return { abbr: "Spray", color: "#22c55e" };
  if (t.includes("nebuliser") || t.includes("nebulizer")) return { abbr: "Neb", color: "#22c55e" };
  if (t.includes("suppository")) return { abbr: "Supp", color: "#eab308" };
  if (t.includes("powder")) return { abbr: "Powder", color: "#94a3b8" };
  if (t.includes("sachet")) return { abbr: "Sachet", color: "#94a3b8" };
  if (t.includes("granules")) return { abbr: "Gran", color: "#94a3b8" };
  if (t.includes("patch")) return { abbr: "Patch", color: "#94a3b8" };
  if (t.includes("shampoo")) return { abbr: "Shampoo", color: "#f59e0b" };
  if (t.includes("mouthwash")) return { abbr: "M/Wash", color: "#22d3ee" };
  if (t.includes("emulsion")) return { abbr: "Emuls", color: "#f472b6" };
  if (t.includes("bar")) return { abbr: "Bar", color: "#94a3b8" };
  return { abbr: String(type).split(" ")[0].slice(0, 6), color: "#94a3b8" };
}

// ম্যানুয়ালি বেছে নেওয়ার জন্য প্রিসেট ধরন তালিকা — যেসব পণ্যের নাম medicineDataset-এ
// নেই (তাই dataset ম্যাচ থেকে dosageForm অটো বসেনি), সেগুলোর জন্য ইউজার নিজে থেকে
// Tab/Cap/Syp ইত্যাদি বেছে দিতে পারবেন — একই medTypeAbbr() ব্যবহার করেই ব্যাজ+রঙ বসে।
