// 🗓️ মেয়াদোত্তীর্ণ/মেয়াদের তারিখ — "X দিন আগে/বাকি" এর বদলে সরাসরি মাস ও সাল
// আকারে দেখানোর জন্য (যেমন "ফেব্রুয়ারি ২০২৬")। অ্যাপের সব জায়গায় এই একটাই
// ফাংশন ব্যবহার হবে যাতে ফরম্যাট সব জায়গায় একরকম থাকে।
const MONTH_NAMES_BN = ["জানুয়ারি","ফেব্রুয়ারি","মার্চ","এপ্রিল","মে","জুন","জুলাই","আগস্ট","সেপ্টেম্বর","অক্টোবর","নভেম্বর","ডিসেম্বর"];
function fmtExpiryMonth(dateStr) {
  if (!dateStr) return "—";
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return "—";
  return `${MONTH_NAMES_BN[d.getMonth()]} ${d.getFullYear()}`;
}
// পূর্ণ লেবেল সহ — মেয়াদ শেষ হয়ে গেছে নাকি এখনো বাকি আছে তা বোঝাতে
function fmtExpiryLabel(dateStr, now = new Date()) {
  if (!dateStr) return "—";
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return "—";
  const monthYear = fmtExpiryMonth(dateStr);
  return d < now ? `⚠️ মেয়াদ শেষ (${monthYear})` : `⏳ মেয়াদ: ${monthYear}`;
}

// ─── 📱 WhatsApp Quick Share — Capacitor Browser দিয়ে wa.me link খোলে ────────
// বাংলাদেশের মোবাইল নম্বর normalize করে — 01XXXXXXXXX → 8801XXXXXXXXX
function normalizeBDMobile(mobile) {
  if (!mobile) return "";
  let m = String(mobile).replace(/[^0-9]/g, "");
  if (m.startsWith("880")) return m;
  if (m.startsWith("0"))   return "88" + m;
  if (m.length === 10)     return "880" + m; // ১XXXXXXXXX ফরম্যাট হলে
  return m;
}

// message নিয়ে PDF ফাইল বানিয়ে শেয়ার-শিট খোলে (WhatsApp সহ যেকোনো অ্যাপে ফাইল হিসেবে যায়) —
// আগে এখানে টেক্সট wa.me লিংক দিয়ে সরাসরি চ্যাট খোলা হতো; এখন অ্যাপের সব জায়গায় WhatsApp
// বাটন থেকে সবসময় শুধু PDF ফাইল যাবে, টেক্সট নয় — তাই এই একটা ফাংশন বদলালেই সব জায়গায় প্রয়োগ হয়।
async function shareViaWhatsApp(mobile, message, showToast) {
  try {
    const shopName = (await load(SK.shopName)) || "SBM";
    const safeMsg = String(message || "").replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/\n/g, "<br/>");
    const html = buildPdfHtml(`<div class="section"><p style="white-space:pre-wrap;font-size:13.5px;line-height:1.9;">${safeMsg}</p></div>`, shopName, "মেসেজ");
    await sharePdfWhatsApp(html, "SBM_মেসেজ");
    showToast?.("শেয়ার সিট খোলা হয়েছে ✓ সেখান থেকে WhatsApp বেছে নিন");
  } catch (e) {
    console.warn("[WhatsApp] share failed:", e);
    showToast?.("শেয়ার করতে সমস্যা হয়েছে", "#ef4444");
  }
}

// ─── 📇 সংরক্ষিত WhatsApp নম্বর — কাস্টমার/সাপ্লায়ারের জন্য ─────────────────
// কাস্টমার/সাপ্লায়ারের নামের বিপরীতে WhatsApp নম্বর একবার দিলে ডিভাইসে (localStorage)
// সংরক্ষিত থাকে — পরেরবার থেকে আর জিজ্ঞেস করা লাগে না, সরাসরি সেই নম্বরে চ্যাট খোলে।
// কাস্টমারের অফিসিয়াল mobile ফিল্ড থাকলে সবসময় সেটাই আগে ব্যবহার হয়; এই ক্যাশ শুধু
// তখনই কাজে লাগে যখন mobile ফাঁকা (বিশেষ করে সাপ্লায়ারের ক্ষেত্রে, যাদের কোনো ফোন-ফিল্ড নেই)।
const WA_CONTACTS_KEY = "sbm_wa_contacts_v1";
function _loadWaContacts() {
  try { return JSON.parse(localStorage.getItem(WA_CONTACTS_KEY) || "{}"); } catch { return {}; }
}
function _saveWaContacts(obj) {
  try { localStorage.setItem(WA_CONTACTS_KEY, JSON.stringify(obj)); } catch {}
}
function getSavedWhatsappNumber(type, name) {
  const key = (name || "").trim();
  if (!key) return "";
  const all = _loadWaContacts();
  return all[`${type}:${key}`] || "";
}
function saveWhatsappNumber(type, name, number) {
  const key = (name || "").trim();
  const num = (number || "").trim();
  if (!key || !num) return;
  const all = _loadWaContacts();
  all[`${type}:${key}`] = num;
  _saveWaContacts(all);
}
// এখন PDF ফাইল শেয়ার-শিটের মাধ্যমে যায় বলে নির্দিষ্ট চ্যাট টার্গেট করার দরকার নেই,
// তাই mobile/সংরক্ষিত নম্বর নির্বিশেষে সরাসরি PDF শেয়ার হয়। প্যারামিটারগুলো পুরোনো
// কল-সাইটের সাথে সামঞ্জস্য রাখতে অপরিবর্তিত রাখা হয়েছে।
async function shareViaWhatsAppSmart(type, name, mobile, message, showToast) {
  return shareViaWhatsApp(mobile, message, showToast);
}

