// ── Voice Search Button ────────────────────────────────────────────────────────
// Web Speech API ব্যবহার করে বাংলা ও ইংলিশ voice input সাপোর্ট করে
function VoiceSearchButton({ onResult, lang = "bn-BD", color = "#22c55e" }) {
  const [listening, setListening] = useState(false);
  const recRef = useRef(null);

  const SpeechRecognition = typeof window !== "undefined" &&
    (window.SpeechRecognition || window.webkitSpeechRecognition);

  // NOTE: early return is AFTER all hooks — Rules of Hooks compliant
  const start = () => {
    if (listening) {
      try { recRef.current?.stop(); } catch {}
      setListening(false);
      return;
    }
    try {
      const rec = new SpeechRecognition();
      rec.lang = lang;
      rec.interimResults = false;
      rec.maxAlternatives = 1;
      rec.onstart  = () => setListening(true);
      rec.onend    = () => setListening(false);
      rec.onerror  = () => setListening(false);
      rec.onresult = (e) => {
        const text = e.results[0][0].transcript;
        if (text) onResult(text);
        setListening(false);
      };
      rec.start();
      recRef.current = rec;
    } catch { setListening(false); }
  };

  if (!SpeechRecognition) return null; // unsupported device — placed after all hooks

  return (
    <button
      onClick={start}
      title={listening ? "শুনছি... (ট্যাপ করুন বন্ধ করতে)" : "ভয়েস সার্চ (বাংলা/English)"}
      style={{
        background: listening ? `${color}22` : "none",
        border: listening ? `1.5px solid ${color}` : "1.5px solid transparent",
        borderRadius: 8, padding: "4px 7px", cursor: "pointer", display: "flex",
        alignItems: "center", gap: 4, color: listening ? color : "#94a3b8",
        animation: listening ? "voicePulse 1s ease-in-out infinite" : "none",
        flexShrink: 0,
      }}
    >
      {listening ? (
        <svg width={16} height={16} viewBox="0 0 24 24" fill={color}>
          <rect x="9" y="2" width="6" height="12" rx="3"/>
          <path d="M5 10a7 7 0 0 0 14 0M12 19v3M8 22h8" stroke={color} strokeWidth="2" fill="none" strokeLinecap="round"/>
        </svg>
      ) : (
        <svg width={16} height={16} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round">
          <rect x="9" y="2" width="6" height="12" rx="3"/>
          <path d="M5 10a7 7 0 0 0 14 0M12 19v3M8 22h8"/>
        </svg>
      )}
      <style>{`@keyframes voicePulse{0%,100%{opacity:1}50%{opacity:0.5}}`}</style>
    </button>
  );
}

// ── #৭ AI ফিচার (পর্যায় ৩) — লেবেলসহ ভয়েস বাটন, VoiceSearchButton-এর একই SpeechRecognition ──
// লজিক কিন্তু টেক্সট-লেবেলড ও disabled/listening কন্ট্রোল করা যায় (বাইরের busy-state এর সাথে সিঙ্কের জন্য)।
function VoiceSearchButtonFull({ onResult, lang = "bn-BD", color = "#a78bfa", label = "🎤 বলুন", disabled = false, listening, onListenChange, style = {} }) {
  const recRef = useRef(null);
  const SpeechRecognition = typeof window !== "undefined" &&
    (window.SpeechRecognition || window.webkitSpeechRecognition);

  const start = () => {
    if (disabled) return;
    if (listening) {
      try { recRef.current?.stop(); } catch {}
      onListenChange(false);
      return;
    }
    try {
      const rec = new SpeechRecognition();
      rec.lang = lang;
      rec.interimResults = false;
      rec.maxAlternatives = 1;
      rec.onstart  = () => onListenChange(true);
      rec.onend    = () => onListenChange(false);
      rec.onerror  = () => onListenChange(false);
      rec.onresult = (e) => {
        const text = e.results[0][0].transcript;
        if (text) onResult(text);
        onListenChange(false);
      };
      rec.start();
      recRef.current = rec;
    } catch { onListenChange(false); }
  };

  if (!SpeechRecognition) return null; // ডিভাইসে সাপোর্ট না থাকলে বাটনই দেখাবে না — early return সব hooks-এর পরে

  return (
    <button type="button" onClick={start} disabled={disabled}
      title={listening ? "শুনছি... (ট্যাপ করুন বন্ধ করতে)" : "বাংলায় বলুন — যেমন: নাপা ৫০০ দশ পিস ক্রয় দশ টাকা বিক্রয় বারো টাকা"}
      style={{
        padding: "7px 8px", borderRadius: 8, cursor: disabled ? "default" : "pointer",
        display: "flex", alignItems: "center", justifyContent: "center", gap: 5,
        fontWeight: 700, fontSize: 12, fontFamily: "inherit",
        border: `1px solid ${color}66`,
        background: listening ? `${color}22` : "transparent",
        color, animation: listening ? "voicePulse 1s ease-in-out infinite" : "none",
        ...style,
      }}>
      {label}
    </button>
  );
}

// ── Live Date & Time display ───────────────────────────────────────────────────
function LiveDateTime({ themeColor = "#fde68a", accentColor = "#7dffc0", compact = true }) {
  const [now, setNow] = useState(new Date());
  useEffect(() => {
    // প্রতি মিনিটে আপডেট — 60x কম re-render (Linear, Notion approach)
    const tick = () => {
      setNow(new Date());
      const ms = 60000 - (Date.now() % 60000);
      timer.current = setTimeout(tick, ms);
    };
    const timer = { current: null };
    timer.current = setTimeout(tick, 60000 - (Date.now() % 60000));
    return () => clearTimeout(timer.current);
  }, []);
  // 🔴 ফিক্স: লাইভ ঘড়ি এখন সবসময় GMT+6 (বাংলাদেশ) সময় দেখায়, ডিভাইসের টাইমজোন যা-ই থাকুক
  const time = now.toLocaleTimeString("en-US", { hour: "2-digit", minute: "2-digit", second: compact ? undefined : "2-digit", timeZone: "Asia/Dhaka" });
  const date = now.toLocaleDateString("en-US", { weekday: "short", month: "short", day: "numeric", timeZone: "Asia/Dhaka" });
  if (compact) {
    // ── কমপ্যাক্ট, এক-লাইন pill — সময় ও তারিখ পাশাপাশি, শপ নামের নিচে আলাদা লাইনে ──
    return (
      <div style={{
        display: "inline-flex", alignItems: "center", gap: 7,
        background: "rgba(0,0,0,0.24)",
        borderRadius: 100,
        padding: "5px 13px",
        backdropFilter: "blur(8px)",
        border: `1px solid ${themeColor}33`,
      }}>
        <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke={themeColor} strokeWidth="2.4" strokeLinecap="round"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>
        <span style={{ color: themeColor, fontWeight: 800, fontSize: 13.5, letterSpacing: 0.4, fontVariantNumeric: "tabular-nums" }}>{time}</span>
        <span style={{ color: `${accentColor}99`, fontSize: 12 }}>•</span>
        <span style={{ color: accentColor, fontWeight: 700, fontSize: 13, letterSpacing: 0.2 }}>{date}</span>
      </div>
    );
  }
  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 5 }}>
      {/* Digital time pill */}
      <div style={{
        display: "flex", alignItems: "center", gap: 7,
        background: "rgba(0,0,0,0.3)",
        borderRadius: 100,
        padding: "5px 14px",
        backdropFilter: "blur(10px)",
        border: `1px solid ${themeColor}44`,
        boxShadow: `0 2px 16px rgba(0,0,0,0.35), 0 0 12px ${themeColor}22, inset 0 1px 0 rgba(255,255,255,0.12)`,
      }}>
        <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke={themeColor} strokeWidth="2.2" strokeLinecap="round"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>
        <span style={{
          color: themeColor,
          fontWeight: 900, fontSize: 15,
          letterSpacing: 1.5,
          textShadow: `0 0 14px ${themeColor}99`,
          fontVariantNumeric: "tabular-nums",
        }}>{time}</span>
      </div>
      {/* Date tag — vibrant accent color */}
      <span style={{
        color: accentColor,
        fontWeight: 800, fontSize: 12,
        letterSpacing: 0.5,
        textShadow: `0 0 10px ${accentColor}88, 0 1px 6px rgba(0,0,0,0.5)`,
        background: `${accentColor}18`,
        borderRadius: 100,
        padding: "2px 10px",
        border: `1px solid ${accentColor}33`,
      }}>📅 {date}</span>
    </div>
  );
}

