  // 🔔 Role-based notification guard — একই ফোনে staff/admin switch হলে
  useEffect(() => {
    if (!loaded) return;
    (async () => {
      try {
        if (!window.Capacitor?.isNativePlatform()) return;
        const { plugin: LocalNotifications } = await Notif._getLocalNotif();
        if (!LocalNotifications) return;

        const cancelIds = Array.from({ length: NOTIF_MAX_TIMES }, (_, i) => ({ id: NOTIF_ID_BASE + i }));

        if (!currentUser || currentUser.role === "staff") {
          // Staff login বা logout — সব scheduled notification বাতিল
          await LocalNotifications.cancel({ notifications: cancelIds });
        } else if (currentUser.role === "admin" || currentUser.role === "owner") {
          // Admin login — notif enabled থাকলে saved times দিয়ে reschedule
          const notifEnabled = localStorage.getItem("notif_enabled") !== "false";
          if (!notifEnabled) return;
          const savedTimesRaw = localStorage.getItem("notif_times");
          let times = [{ hour: 22, minute: 0 }];
          if (savedTimesRaw) {
            try {
              const parsed = JSON.parse(savedTimesRaw);
              if (Array.isArray(parsed) && parsed.length > 0) times = parsed;
            } catch {}
          }
          // 🔴 ফিক্স — permission-check fallback বাদ দেওয়া হলো (sendTestNotif ও
          // rescheduleAll-এ যেমন করা হয়েছে)। বারবার প্রমাণিত হয়েছে requestPermission()
          // এই ডিভাইসে চিরকাল hang করে — তাই এটা রাখলে শুধু প্রতিবার role-switch হলে
          // ১৫ সেকেন্ড নিঃশব্দে আটকে থাকত, কোনো লাভ ছাড়াই। এখন সরাসরি schedule()
          // ট্রাই হবে, ব্যর্থ হলে কারণটা console-এ log হবে।
          const doScheduleAll = async () => {
            await LocalNotifications.cancel({ notifications: cancelIds });
            // 🔴 ফিক্স: আগে এখানে একটা জেনেরিক/ফাঁকা বডি ("${shopName} • দৈনিক রিপোর্ট",
            // কোনো বিক্রয়/নগদ/বাকির হিসাব ছাড়া) দিয়ে রিশিডিউল হতো, যা DailyNotifCard-এর
            // আসল হিসাবসহ নোটিফিকেশনকে ওভাররাইট করে ফেলত। এখন একই শেয়ার্ড
            // buildDailySummaryData/buildDailySummaryNotifContent ব্যবহার করা হচ্ছে,
            // তাই নোটিফিকেশন সবসময় আসল বিক্রয়/নগদ/বাকির হিসাবসহ দেখাবে।
            const sum = buildDailySummaryData({ invoices, txns, customers, products, cashLogs, purchaseOrders });
            const { body, largeBody } = buildDailySummaryNotifContent(sum);
            for (let i = 0; i < Math.min(times.length, NOTIF_MAX_TIMES); i++) {
              const t = times[i];
              await Notif.send({
                id: NOTIF_ID_BASE + i,
                title: `✨ ${shopName} — আজকের সারসংক্ষেপ`,
                iconColor: "#8b5cf6",
                body,
                largeBody,
                summaryText: `${shopName} • দৈনিক রিপোর্ট ✨`,
                repeatDailyAt: { hour: t.hour, minute: t.minute },
              });
            }
          };
          try {
            await doScheduleAll();
          } catch (e) {
            console.warn("[NotifGuard] doScheduleAll failed:", e?.message || e);
          }
        }
      } catch (e) {
        console.warn("[NotifGuard] role switch handler error:", e?.message || e);
      }
    })();
  }, [currentUser?.role, loaded]); // eslint-disable-line react-hooks/exhaustive-deps
