      fontSize: fs(16),
      display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
      boxShadow: `0 4px 18px ${T.accentGlow}`,
      transition: "all 0.2s cubic-bezier(0.4,0,0.2,1)",
